import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { coursesService } from '../../services/courses';
import { authService } from '../../services/auth';
import './Dashboard.css';

const InstructorDashboard = () => {
  const navigate = useNavigate();
  const [courses, setCourses]         = useState([]);
  const [loading, setLoading]         = useState(true);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [formData, setFormData]       = useState({ title: '', description: '', price: '', image: null });
  const [submitting, setSubmitting]   = useState(false);
  const [error, setError]             = useState('');

  const user = authService.getUserFromStorage();

  useEffect(() => { loadCourses(); }, []);

  const loadCourses = async () => {
    try {
      setLoading(true);
      const u = authService.getUserFromStorage();
      const data = await coursesService.getAll({ instructor: u?.id });
      setCourses(Array.isArray(data) ? data : (data.results || []));
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    if (e.target.name === 'image') {
      setFormData({ ...formData, image: e.target.files[0] });
    } else {
      setFormData({ ...formData, [e.target.name]: e.target.value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSubmitting(true);
    try {
      await coursesService.create(formData);
      setShowCreateForm(false);
      setFormData({ title: '', description: '', price: '', image: null });
      loadCourses();
    } catch (err) {
      const errorData = err.response?.data;
      setError(typeof errorData === 'object'
        ? Object.values(errorData).flat().join(', ')
        : 'Failed to create course');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div>
          <h1>Instructor Dashboard</h1>
          <p className="dashboard-subtitle">Manage your courses and track their approval status</p>
        </div>
        <div className="dashboard-actions">
          <button onClick={() => setShowCreateForm(!showCreateForm)} className="btn btn-primary">
            {showCreateForm ? 'إلغاء' : '+ إنشاء كورس جديد'}
          </button>
          {user?.is_staff && (
            <button onClick={() => navigate('/admin/courses')} className="btn btn-outline">
              🛂 مراجعة الكورسات
            </button>
          )}
        </div>
      </div>

      {showCreateForm && (
        <div className="create-course-form">
          <h2>إنشاء كورس جديد</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>العنوان *</label>
              <input type="text" name="title" value={formData.title} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label>الوصف *</label>
              <textarea name="description" value={formData.description} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label>السعر *</label>
              <input type="number" name="price" step="0.01" min="0" value={formData.price} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label>صورة الكورس</label>
              <input type="file" name="image" accept="image/*" onChange={handleChange} />
            </div>
            {error && <div className="error-message">{error}</div>}
            <button type="submit" className="btn btn-primary" disabled={submitting}>
              {submitting ? 'جاري الإنشاء...' : 'إنشاء الكورس'}
            </button>
          </form>
        </div>
      )}

      <h2>كورساتي</h2>
      {courses.length === 0 ? (
        <div className="empty-state">
          <p>لم تقم بإنشاء أي كورسات بعد.</p>
        </div>
      ) : (
        <div className="courses-grid">
          {courses.map((course) => (
            <div key={course.id} className="course-card">
              {/* Course image / info – click to view */}
              <div onClick={() => navigate(`/courses/${course.id}`)} style={{ cursor: 'pointer' }}>
                {course.image_url
                  ? <img src={course.image_url} alt={course.title} />
                  : <div className="course-image-placeholder">No Image</div>}
                <div className="course-info">
                  <h3>{course.title}</h3>
                  <p className="course-status">
                    Status:{' '}
                    {course.is_approved
                      ? <span className="status-approved">✓ معتمد ومنشور</span>
                      : <span className="status-pending">⏳ في انتظار الموافقة</span>}
                  </p>
                  <span className="course-price">{parseFloat(course.price).toFixed(2)} EGP</span>
                </div>
              </div>

              {/* Manage button */}
              <div style={{ padding: '0 12px 12px', display: 'flex', gap: 8 }}>
                <button
                  style={btnManage}
                  onClick={() => navigate(`/courses/${course.id}/manage`)}
                >
                  ⚙ إدارة المحتوى
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const btnManage = {
  flex: 1, padding: '8px 0', background: '#f0f4ff', color: '#0066cc',
  border: '1px solid #c0d4ff', borderRadius: 6, cursor: 'pointer',
  fontWeight: 600, fontSize: 13,
};

export default InstructorDashboard;
